INSERT INTO healthcare_providers (
    id, name, name_az, name_en, specialty, specialty_az, specialty_en, city, provider_type, is_active, website, image_url, description, description_az, description_en, address, address_az, address_en, phone, rating, review_count
) VALUES (
    '0316cec0-4286-47d9-a7ed-c1d2468cf313', 
    'Dr. Mədinə Dilbazi', 
    'Dr. Mədinə Dilbazi', 
    'Dr. Mədinə Dilbazi', 
    'Endokrinoloq', 
    'Endokrinoloq', 
    'Endokrinoloq', 
    'Bakı', 
    'doctor', 
    true, 
    'https://www.instagram.com/endokrinoloq.medine.dilbazi/ ', 
    'https://api.doktorsitesi.az/media/cache/profil_500_webp/uploads/profile_self_image/208934c8bd1b881dac1f7d0730812bbc.webp',
    E'Təcrübə: 16 il\nDillər: Azərbaycan Dili\nTəhsil: Azərbaycan Dövlət Tibb Universiteti\nMaraq sahələri: Dislipidemiyalar (qan yağları) ,  Artıq çəki və piylənmə ,  Metabolik sindrom ,  Piylənmə ,  Şəkərli diabet tip 1 və tip 2 ,  Tiroid vəzin aspirasiyası ,  Böyrəküstü vəzi xəstəlikləri ,  Cinsi vəzilərin xəstəlikləri- endokrin sonsuzluq (PCOS, KAH, CGB) ,  Hipofiz vəzi xəstəlikəri ,  Osteoporoz və sümük metobolizma xəstəlikləri\n\nDr. Mədinə Dilbazi endokrinologiya və dietologiya sahəsində 15 ildən artıq klinik təcrübəyə malik mütəxəssisdir. Hazırda Leyla Medical Center-də endokrinoloq-diyetoloq kimi fəaliyyət göstərərək hormon sistemi xəstəliklərinin diaqnostikası, müalicəsi və uzunmüddətli izlənməsi ilə məşğul olur. 2004–2010-cu illərdə Azərbaycan Tibb Universitetinin Müalicə işi fakültəsində təhsil almış, 2011-ci ildə 4 saylı Şəhər Klinik Xəstəxanasında endokrinologiya üzrə internaturanı tamamlamışdır. Daha sonra Türkiyənin Ege Universitetində endokrinologiya və metabolizma üzrə ixtisasartırma kursları keçərək diabet, qalxanabənzər vəzi xəstəlikləri, dietologiya, osteoporoz və metabolik xəstəliklər sahəsində bilik və bacarıqlarını inkişaf etdirmişdir. Peşəkar fəaliyyəti boyunca Türkiyə Endokrin və Metabolizma Dərnəyinin (TEMD) konfranslarında, bariatrik və metabolik cərrahiyyə üzrə elmi tədbirlərdə, həmçinin beynəlxalq endokrinologiya və piylənmə mövzusunda keçirilən konqreslərdə iştirak etmişdir. Müasir diaqnostika və müalicə protokollarını gündəlik klinik praktikada tətbiq edərək hər bir pasiyent üçün fərdiləşdirilmiş müalicə planı hazırlayır. Dr. Mədinə Dilbazi xüsusilə piylənmə, şəkərli diabet və qalxanabənzər vəzi xəstəliklərinin kompleks idarə olunması sahəsində ixtisaslaşıb. Pasiyent yönümlü yanaşması, elmi əsaslara söykənən müalicə prinsipləri və davamlı peşəkar inkişafı sayəsində endokrinologiya sahəsində etibarlı mütəxəssislərdən biri kimi fəaliyyətini davam etdirir.',
    E'Təcrübə: 16 il\nDillər: Azərbaycan Dili\nTəhsil: Azərbaycan Dövlət Tibb Universiteti\nMaraq sahələri: Dislipidemiyalar (qan yağları) ,  Artıq çəki və piylənmə ,  Metabolik sindrom ,  Piylənmə ,  Şəkərli diabet tip 1 və tip 2 ,  Tiroid vəzin aspirasiyası ,  Böyrəküstü vəzi xəstəlikləri ,  Cinsi vəzilərin xəstəlikləri- endokrin sonsuzluq (PCOS, KAH, CGB) ,  Hipofiz vəzi xəstəlikəri ,  Osteoporoz və sümük metobolizma xəstəlikləri\n\nDr. Mədinə Dilbazi endokrinologiya və dietologiya sahəsində 15 ildən artıq klinik təcrübəyə malik mütəxəssisdir. Hazırda Leyla Medical Center-də endokrinoloq-diyetoloq kimi fəaliyyət göstərərək hormon sistemi xəstəliklərinin diaqnostikası, müalicəsi və uzunmüddətli izlənməsi ilə məşğul olur. 2004–2010-cu illərdə Azərbaycan Tibb Universitetinin Müalicə işi fakültəsində təhsil almış, 2011-ci ildə 4 saylı Şəhər Klinik Xəstəxanasında endokrinologiya üzrə internaturanı tamamlamışdır. Daha sonra Türkiyənin Ege Universitetində endokrinologiya və metabolizma üzrə ixtisasartırma kursları keçərək diabet, qalxanabənzər vəzi xəstəlikləri, dietologiya, osteoporoz və metabolik xəstəliklər sahəsində bilik və bacarıqlarını inkişaf etdirmişdir. Peşəkar fəaliyyəti boyunca Türkiyə Endokrin və Metabolizma Dərnəyinin (TEMD) konfranslarında, bariatrik və metabolik cərrahiyyə üzrə elmi tədbirlərdə, həmçinin beynəlxalq endokrinologiya və piylənmə mövzusunda keçirilən konqreslərdə iştirak etmişdir. Müasir diaqnostika və müalicə protokollarını gündəlik klinik praktikada tətbiq edərək hər bir pasiyent üçün fərdiləşdirilmiş müalicə planı hazırlayır. Dr. Mədinə Dilbazi xüsusilə piylənmə, şəkərli diabet və qalxanabənzər vəzi xəstəliklərinin kompleks idarə olunması sahəsində ixtisaslaşıb. Pasiyent yönümlü yanaşması, elmi əsaslara söykənən müalicə prinsipləri və davamlı peşəkar inkişafı sayəsində endokrinologiya sahəsində etibarlı mütəxəssislərdən biri kimi fəaliyyətini davam etdirir.',
    E'Təcrübə: 16 il\nDillər: Azərbaycan Dili\nTəhsil: Azərbaycan Dövlət Tibb Universiteti\nMaraq sahələri: Dislipidemiyalar (qan yağları) ,  Artıq çəki və piylənmə ,  Metabolik sindrom ,  Piylənmə ,  Şəkərli diabet tip 1 və tip 2 ,  Tiroid vəzin aspirasiyası ,  Böyrəküstü vəzi xəstəlikləri ,  Cinsi vəzilərin xəstəlikləri- endokrin sonsuzluq (PCOS, KAH, CGB) ,  Hipofiz vəzi xəstəlikəri ,  Osteoporoz və sümük metobolizma xəstəlikləri\n\nDr. Mədinə Dilbazi endokrinologiya və dietologiya sahəsində 15 ildən artıq klinik təcrübəyə malik mütəxəssisdir. Hazırda Leyla Medical Center-də endokrinoloq-diyetoloq kimi fəaliyyət göstərərək hormon sistemi xəstəliklərinin diaqnostikası, müalicəsi və uzunmüddətli izlənməsi ilə məşğul olur. 2004–2010-cu illərdə Azərbaycan Tibb Universitetinin Müalicə işi fakültəsində təhsil almış, 2011-ci ildə 4 saylı Şəhər Klinik Xəstəxanasında endokrinologiya üzrə internaturanı tamamlamışdır. Daha sonra Türkiyənin Ege Universitetində endokrinologiya və metabolizma üzrə ixtisasartırma kursları keçərək diabet, qalxanabənzər vəzi xəstəlikləri, dietologiya, osteoporoz və metabolik xəstəliklər sahəsində bilik və bacarıqlarını inkişaf etdirmişdir. Peşəkar fəaliyyəti boyunca Türkiyə Endokrin və Metabolizma Dərnəyinin (TEMD) konfranslarında, bariatrik və metabolik cərrahiyyə üzrə elmi tədbirlərdə, həmçinin beynəlxalq endokrinologiya və piylənmə mövzusunda keçirilən konqreslərdə iştirak etmişdir. Müasir diaqnostika və müalicə protokollarını gündəlik klinik praktikada tətbiq edərək hər bir pasiyent üçün fərdiləşdirilmiş müalicə planı hazırlayır. Dr. Mədinə Dilbazi xüsusilə piylənmə, şəkərli diabet və qalxanabənzər vəzi xəstəliklərinin kompleks idarə olunması sahəsində ixtisaslaşıb. Pasiyent yönümlü yanaşması, elmi əsaslara söykənən müalicə prinsipləri və davamlı peşəkar inkişafı sayəsində endokrinologiya sahəsində etibarlı mütəxəssislərdən biri kimi fəaliyyətini davam etdirir.',
    'Leyla Medical Center, Y. Səfəroğlu 19Y. Səfəroğlu 19',
    'Leyla Medical Center, Y. Səfəroğlu 19Y. Səfəroğlu 19',
    'Leyla Medical Center, Y. Səfəroğlu 19Y. Səfəroğlu 19',
