INSERT INTO healthcare_providers (
    id, name, name_az, name_en, specialty, specialty_az, specialty_en, city, provider_type, is_active, website, image_url, description, description_az, description_en, address, address_az, address_en, phone, rating, review_count
) VALUES (
    '211a59f8-e8a8-447c-94f9-806f7c02a5d8', 
    'Dr. Aynurə İbrahimova', 
    'Dr. Aynurə İbrahimova', 
    'Dr. Aynurə İbrahimova', 
    'Uşaq nevrologiyası', 
    'Uşaq nevrologiyası', 
    'Uşaq nevrologiyası', 
    'Bakı', 
    'doctor', 
    true, 
    'https://www.instagram.com/nevroloq____dr.aynura''', 
    'https://api.doktorsitesi.az/media/cache/profil_500_webp/uploads/profile_self_image/9778ffb1a35d83eb5ababd28709d9607.webp',
    E'Təcrübə: 27 il\nDillər: Azərbaycan Dili\nTəhsil: Azərbaycan Dövlət Tibb Universiteti\nMagistr: Azərbaycan Dövlət Tibb Universiteti\nMaraq sahələri: Uşaqlarda və yeniyetmələrdə 0-18 yaş qrupnda kəkələmə\n\nDr. Aynurə İbrahimova , 1993–1999-cu illərdə Azərbaycan Tibb Universitetində ali tibb təhsili almışdır. 1999–2000-ci illərdə Azərbaycan Tibb Universitetində nevrologiya ixtisası üzrə internatura keçərək həkim-nevroloq kimi peşəkar fəaliyyətə başlamışdır. 2000–2003-cü illərdə Zaqatala Mərkəzi Rayon Xəstəxanasında həkim-nevroloq kimi çalışmışdır. 2004–2021-ci illər ərzində Şəfa Müalicə-Diaqnostika Mərkəzində fəaliyyət göstərərək nevroloji xəstəliklərin diaqnostika və müalicəsi sahəsində geniş təcrübə qazanmışdır. Peşəkar inkişafına daim önəm verən mütəxəssis Türkiyənin aparıcı universitet və tibb müəssisələrində ixtisasartırma proqramlarında iştirak etmişdir. Ankara şəhərində yerləşən Başkent Universitetinin Nevrologiya Ana Bilim Dalında, EEG və Nevrologiya Poliklinikasında müşahidəçi həkim kimi fəaliyyət göstərmişdir. Həmçinin İstanbul Marmara Universitetinin Nevrologiya Ana Bilim Dalının EMQ (Elektromioqrafiya) Poliklinikasında müşahidəçi olaraq təcrübə keçmişdir. 2017-ci ilin oktyabr-noyabr aylarında Ankara şəhərində yerləşən Qazi Universitetinin Neyrofiziologiya Poliklinikasında müşahidəçi həkim kimi iştirak edərək neyrofizioloji diaqnostika sahəsində bilik və bacarıqlarını təkmilləşdirmişdir. Hazırda uşaq nevrologiyası sahəsində fəaliyyət göstərən həkim uşaqlarda sinir sistemi xəstəliklərinin diaqnostikası, müalicəsi və uzunmüddətli izlənməsi ilə məşğul olur. Elmi yenilikləri və müasir müalicə metodlarını daim izləyərək pasiyentlərinə fərdi yanaşma əsasında tibbi xidmət göstərir.',
